## 基本 async
```rust
// Cargo.toml
// tokio = { version = "1", features = ["full"] }

use tokio::time::{sleep, Duration};

#[tokio::main]
async fn main() {
    println!("Start");
    sleep(Duration::from_secs(1)).await;
    println!("After 1 sec");
}
```

## 並發
```rust
use tokio::time::{sleep, Duration};

#[tokio::main]
async fn main() {
    // 序列：3 秒
    let r1 = task1().await;
    let r2 = task2().await;
    let r3 = task3().await;

    // 並發：1 秒
    let (r1, r2, r3) = tokio::join!(task1(), task2(), task3());
}

async fn task1() -> u32 {
    sleep(Duration::from_secs(1)).await;
    1
}
```

## spawn（背景任務）
```rust
let handle = tokio::spawn(async {
    sleep(Duration::from_secs(1)).await;
    42
});

println!("doing other things...");
let result = handle.await.unwrap();
println!("result: {}", result);
```

## HTTP 請求（reqwest）
```rust
// Cargo.toml: reqwest = { version = "0.12", features = ["json"] }
use serde::Deserialize;

#[derive(Deserialize, Debug)]
struct User { name: String }

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let user: User = reqwest::get("https://api.github.com/users/luffysky")
        .await?
        .json()
        .await?;
    println!("{:?}", user);
    Ok(())
}
```

## 多個並發 fetch
```rust
use futures::future::join_all;

let urls = vec!["https://a.com", "https://b.com", "https://c.com"];
let results = join_all(urls.into_iter().map(|url| async move {
    reqwest::get(url).await
})).await;
```

## Stream（類似 Node Streams）
```rust
use futures::stream::{self, StreamExt};

let stream = stream::iter(1..=10)
    .map(|n| async move {
        sleep(Duration::from_millis(100)).await;
        n * 2
    })
    .buffer_unordered(5);  // 並發 5 個

let results: Vec<i32> = stream.collect().await;
```

