## Hello World
```rust
// Cargo.toml
// axum = "0.7"
// tokio = { version = "1", features = ["full"] }
// serde = { version = "1", features = ["derive"] }

use axum::{routing::get, Router, Json};
use serde::Serialize;

#[derive(Serialize)]
struct Hello { message: String }

async fn root() -> Json<Hello> {
    Json(Hello { message: "Hello Axum".into() })
}

#[tokio::main]
async fn main() {
    let app = Router::new().route("/", get(root));

    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
    axum::serve(listener, app).await.unwrap();
}
```

## 動態路由 + Query
```rust
use axum::extract::{Path, Query};
use serde::Deserialize;

#[derive(Deserialize)]
struct Pagination { page: Option<u32> }

async fn user(Path(id): Path<u32>) -> String {
    format!("User {}", id)
}

async fn list(Query(p): Query<Pagination>) -> String {
    format!("Page {}", p.page.unwrap_or(1))
}

let app = Router::new()
    .route("/users/:id", get(user))
    .route("/posts", get(list));
```

## POST + JSON body
```rust
use axum::{routing::post, Json};
use serde::{Serialize, Deserialize};

#[derive(Deserialize)]
struct CreateUser { name: String, age: u32 }

#[derive(Serialize)]
struct User { id: u32, name: String }

async fn create(Json(payload): Json<CreateUser>) -> Json<User> {
    Json(User { id: 1, name: payload.name })
}
```

## Middleware（tower）
```rust
use axum::{Router, middleware};
use tower_http::cors::CorsLayer;
use tower_http::trace::TraceLayer;

let app = Router::new()
    .route("/", get(root))
    .layer(CorsLayer::permissive())
    .layer(TraceLayer::new_for_http());
```

## State（共享資料）
```rust
use std::sync::Arc;
use axum::extract::State;

#[derive(Clone)]
struct AppState { db_pool: Pool }

async fn handler(State(state): State<AppState>) -> String {
    let users = state.db_pool.query("SELECT ...").await;
    format!("{} users", users.len())
}

let state = AppState { db_pool };
let app = Router::new().route("/", get(handler)).with_state(state);
```

## sqlx（type-safe DB）
```rust
use sqlx::PgPool;

#[derive(sqlx::FromRow, Serialize)]
struct User { id: i32, name: String }

async fn users(State(pool): State<PgPool>) -> Json<Vec<User>> {
    let users: Vec<User> = sqlx::query_as!(User, "SELECT id, name FROM users")
        .fetch_all(&pool)
        .await
        .unwrap();
    Json(users)
}
```
編譯時連 DB 驗證 SQL！

